 1	#!/usr/bin/env node
 2	/**
 3	 * Capture raw wire output for documentation.
 4	 * Run: node scripts/capture-wire-output.js
 5	 * Output: docs/wire-output-sample.jsonl
 6	 */
 7	const { spawn } = require('child_process');
 8	const fs = require('fs');
 9	const path = require('path');
10	
11	const OUTPUT_PATH = path.join(__dirname, '..', 'docs', 'wire-output-sample.jsonl');
12	const PROMPT = process.argv[2] || 'What is 2 + 2? Think step by step.';
13	const TIMEOUT_MS = 30000; // 30 seconds max
14	
15	const kimiPath = process.env.KIMI_PATH || 'kimi';
16	const wire = spawn(kimiPath, ['--wire', '--yolo'], {
17	  stdio: ['pipe', 'pipe', 'inherit']
18	});
19	
20	const lines = [];
21	let sawTurnEnd = false;
22	
23	function send(msg) {
24	  const json = JSON.stringify(msg) + '\n';
25	  wire.stdin.write(json);
26	}
27	
28	wire.stdout.on('data', (data) => {
29	  const text = data.toString();
30	  const chunkLines = text.split('\n').filter((l) => l.trim());
31	  for (const line of chunkLines) {
32	    lines.push(line);
33	    try {
34	      const msg = JSON.parse(line);
35	      if (msg.method === 'event' && msg.params?.type === 'TurnEnd') {
36	        sawTurnEnd = true;
37	      }
38	    } catch (_) {}
39	  }
40	});
41	
42	wire.on('error', (err) => {
43	  console.error('[capture-wire] Spawn error:', err.message);
44	  process.exit(1);
45	});
46	
47	// Initialize then prompt
48	send({
49	  jsonrpc: '2.0',
50	  method: 'initialize',
51	  id: 'init-1',
52	  params: {
53	    protocol_version: '1.4',
54	    client: { name: 'capture-script', version: '0.1.0' },
55	    capabilities: {}
56	  }
57	});
58	
59	setTimeout(() => {
60	  send({
61	    jsonrpc: '2.0',
62	    method: 'prompt',
63	    id: 'prompt-1',
64	    params: { user_input: PROMPT }
65	  });
66	}, 500);
67	
68	// Stop after TurnEnd or timeout
69	const checkInterval = setInterval(() => {
70	  if (sawTurnEnd) {
71	    clearInterval(checkInterval);
72	    wire.kill('SIGTERM');
73	    finish();
74	  }
75	}, 200);
76	
77	setTimeout(() => {
78	  clearInterval(checkInterval);
79	  wire.kill('SIGTERM');
80	  finish();
81	}, TIMEOUT_MS);
82	
83	function finish() {
84	  const outDir = path.dirname(OUTPUT_PATH);
85	  if (!fs.existsSync(outDir)) fs.mkdirSync(outDir, { recursive: true });
86	  fs.writeFileSync(OUTPUT_PATH, lines.join('\n') + '\n', 'utf8');
87	  console.log(`[capture-wire] Wrote ${lines.length} lines to ${OUTPUT_PATH}`);
88	  process.exit(0);
89	}
